// 10 Podcast Clip Captions 🎙️🔥
const captions = [
$('Download file').first().json.Caption
];

// Pick random caption
const randomIndex = Math.floor(Math.random() * captions.length);
const fullText = captions[randomIndex];

// Extract hashtags
const hashtagsMatch = fullText.match(/#[\w]+/g) || [];

// Remove hashtags from caption
const captionText = fullText.replace(/#[\w]+/g, "").trim();

return [
  {
    json: {
      caption: captionText,
      hashtags: hashtagsMatch.join(" ")
    }
  }
];
